var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"피터 버렌입니다.","JPN":"ピーター・バーレンです。","ENG":"Peter Burren here.","TWN":"我是彼得·弗倫。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"저희 기업은 나날이 상승곡선을 그리며 성장하고 있습니다.","JPN":"弊社は日々上昇曲線を描きながら成長しています。","ENG":"The Iron Tailors is growing in size day by day.","TWN":"我們公司正在以日新月異的速度成長著。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"머지않아 아이언 테일러는 세계적인 군수기업이 될 테고, 놈들은 제 발밑을 설설 기게 되겠죠.","JPN":"近いうちにアイアンテイラーは世界的な軍需企業になり、他社は弊社に対して頭が上がらなくなるでしょう。","ENG":"It won't be long before we are renowned throughout the world and those that consider themselves our rivals kneel before us.","TWN":"鋼鐵泰勒很快就會成為世界聞名的軍工企業，那些傢伙都會在我腳下搖尾乞憐吧。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 발밑을 기는 건 저희와 경쟁하는 다른 업체들 얘기입니다. 오해하지 마세요.","JPN":"アハハハ、他社というのは競合他社のことです。くれぐれも誤解しませんように。","ENG":"Ah, please don't get me wrong. I'm talking about companies trying to compete with us, not yours.","TWN":"哈哈，我說的是其它與我們競爭的企業。請不要誤會。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 처음 군수사업에 뛰어들었을 땐, 그 터줏대감들에게 옷장사나 하던 근본 없는 문어발 회사라며 비아냥을 많이 들었거든요.","JPN":"弊社が初めて軍需事業に参入した時、古参の競合他社からは基盤もない小さなアパレルメーカーが軍需に手を出したと、散々嫌味を言われたものでしてね。","ENG":"They all mocked us when we first jumped into the munitions industry, saying we were nothing but clothes traders desperately trying to make a buck in a field we hardly knew.","TWN":"剛開始榻進軍工企業時，經常聽那些老牌企業嘲笑我們，說我們以前是賣衣服的，沒有根源只會擴張公司。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 지금은 어떻습니까?","JPN":"しかし現状は？","ENG":"But look how things turned out!","TWN":"但如今呢？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 놈들은 저희와 기술을 공유하고 싶다며 뻔뻔하게 거래를 제안해오고 있습니다.","JPN":"彼らは弊社と技術を共有したいと、厚かましく取引を提案してきているのです。","ENG":"Those bastards are brazenly offering business deals, asking us to share information.","TWN":"如今那些傢伙為了和我們共用技術，厚著臉皮提出要與我們進行交易。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하, 자존심도 없는 머저리들 같으니.","JPN":"ハハハ、プライドもクソもない間抜けな連中です。","ENG":"Those gutless, prideless jerks.","TWN":"哈哈哈，像群毫無自尊心可言的笨蛋。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"......아 참, 어제 저희 신소재 방호복에 사소한 결함이 발견됐더군요.","JPN":"……そういえば、昨日弊社の新素材防護服に些細な欠陥が見つかりました。","ENG":"Ah, have you heard they found a minor flaw on our brand new protective suit yesterday?","TWN":"……啊，對了，目前我們發現新型防護服有一個小小的缺陷。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"블랙네트워크에 샘플을 몇 개 풀어놓고 경과를 지켜봤는데, 방호복에서 미량의 침식파가 검출됐다고 하네요.","JPN":"ブラックネットワークにサンプルをいくつか流して経過を観察しましたが、防護服から微量の侵食波が検出されたそうです。","ENG":"We released a few samples on the Dark Network to see how the market would react, and it turns out the suit is emitting a very subtle Corruption ray.","TWN":"我們在黑色網路放出幾個樣品觀察了一下，結果防護服裡檢測出了微量的侵蝕波呢。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"고작 그런 걸로 사람이 죽진 않겠지만...... 말씀 드렸다시피 도시관리국의 안정성 검증은 꽤 까다로운 편이라서요.","JPN":"たかだかその程度で人が死ぬことはありませんが……以前申し上げたように都市管理局の安全性検証はかなり厳しい方でしてね。","ENG":"It won't kill anyone, but... Like I told you before, the City Management are pretty fastidious with their safety tests.","TWN":"雖然不足以致人死亡……但如我方才所言，城市管理局的安全性檢驗比較麻煩。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"책정비용이 다소 올라가긴 하겠지만, 방호복의 침식파를 완전히 억제하려면 이터니움 비중을 좀 더 높여야 할 것 같습니다.","JPN":"策定費用が多少上がることになりますが、防護服の侵食波を完全に抑制するためにはエタニウムの割合をもっと高める必要があるそうです。","ENG":"We'll have to raise the rate of Eternium slightly to suppress the emission of Corruption ray. I'm afraid this might result in a price hike.","TWN":"雖然定價可能會再高一些，但若要完全抑制防護服中的侵蝕波，就必須提高永恆之金比重了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 기왕 새로 제작하는 김에 이번에는 좀 더 좋은 소재를 활용해보고 싶군요.","JPN":"そしてせっかく作り直すなら、今回はもう少し良い素材を活用してみたいと思います。","ENG":"And while we're at it, we'd like to build samples with even better base materials.","TWN":"既然要重新製作，這次想試試看更好的素材啊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"행운을 빕니다.","JPN":"幸運を祈ります。","ENG":"Good luck.","TWN":"祝您好運。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};